<template>
    <v-container>
        <PagePath />
        <div class="content">
            <div class="list_options">
                <div class="btn_area">
                    <span class="txt_term">날 짜</span>
                    <v-menu
                        ref="menu"
                        v-model="isPickerOpen"
                        :close-on-content-click="false"
                        :return-value.sync="dates"
                        transition="scale-transition"
                        offset-y
                    >
                        <template v-slot:activator="{ on, attrs }">
                            <div>
                                <v-text-field
                                    v-model="dateRangeText"
                                    v-bind="attrs"
                                    v-on="on"
                                    outlined
                                    prepend-inner-icon="mdi-calendar"
                                    readonly
                                    hide-details
                                    class="white"
                                />
                            </div>
                        </template>
                        <v-date-picker v-model="dates" range no-title>
                            <v-spacer></v-spacer>
                            <v-btn text color="primary" @click="isPickerOpen = false"> 취소 </v-btn>
                            <v-btn text color="primary" @click="$refs.menu.save(dates)"> 확인 </v-btn>
                        </v-date-picker>
                    </v-menu>
                    <v-btn elevation="3" color="primary" class="btn_search" outlined @click="doSearch">찾기</v-btn>
                    <div class="category">
                        <v-btn
                            @click="doChangeLogType(null)"
                            :outlined="selectedLogType !== null"
                            class="btn_all"
                            color="#FFCC00"
                            primary
                            elevation="3"
                            >전체보기</v-btn
                        >
                        <v-btn
                            @click="doChangeLogType('I')"
                            :outlined="selectedLogType !== 'I'"
                            class="btn_info"
                            color="#3DCD0D"
                            primary
                            elevation="3"
                            >정보성</v-btn
                        >
                        <v-btn
                            @click="doChangeLogType('N')"
                            :outlined="selectedLogType !== 'N'"
                            class="btn_alarm"
                            color="#2A85FF"
                            primary
                            elevation="3"
                            >알 림</v-btn
                        >
                        <v-btn
                            @click="doChangeLogType('W')"
                            :outlined="selectedLogType !== 'W'"
                            class="btn_alert"
                            color="#CC0C0C"
                            primary
                            elevation="3"
                            >경보성</v-btn
                        >
                        <v-btn
                            @click="doChangeLogType('E')"
                            :outlined="selectedLogType !== 'E'"
                            class="btn_error"
                            color="#FD9D0D"
                            primary
                            elevation="3"
                            >에 러</v-btn
                        >
                    </div>
                    <!-- <button class="btn_xls" :disabled="checkNum.length === 0" @click="checkData()"></button>
                    <button class="btn_pdf" :disabled="checkNum.length === 0" @click="checkData()"></button> -->
                    <button class="btn_xls" :disabled="checkNum.length === 0" @click="doExcelDownload()"></button>
                    <button class="btn_pdf" :disabled="checkNum.length === 0" @click="doPdfDownload()"></button>
                    <v-select
                        outlined
                        v-model="rowsPerPage"
                        :items="itemsPerPage"
                        item-text="label"
                        item-value="value"
                        placeholder="10개씩 보기"
                        v-on:change="doSearch()"
                        hide-details
                        class="white view_length"
                    />
                </div>
            </div>
            <v-data-table
                id="table"
                v-model="selectedRows"
                :loading="isLoading"
                item-key="PPA_LOG_ID"
                checkbox-color="primary"
                :headers="headers"
                :items="dataList"
                :items-per-page="rowsPerPage"
                no-data-text="데이터가 존재하지 않습니다."
                hide-default-footer
                :server-items-length="numOfAllData"
                :options.sync="options"
                :sort-by.sync="sortBy"
                :sort-desc.sync="sortDesc"
            >
                <template #item="{ item }">
                    <tr>
                        <td>
                            <v-checkbox :value="item.idx" @click="selectList()" />
                        </td>
                        <td>{{ item.PPA_LOG_ID }}</td>
                        <td>{{ getTimestamp(item.CREATED) }}</td>
                        <td>
                            <span class="cate_info" v-if="item.LOG_TYPE === 'I'">정보성</span>
                            <span class="cate_alarm" v-if="item.LOG_TYPE === 'N'">알림</span>
                            <span class="cate_alert" v-if="item.LOG_TYPE === 'W'">경보성</span>
                            <span class="cate_error" v-if="item.LOG_TYPE === 'E'">에러</span>
                        </td>
                        <td>{{ item.LOG_DESC }}</td>
                    </tr>
                </template>
            </v-data-table>
            <v-col class="pagination">
                <v-pagination v-model="pageNo" :length="numOfPages" :total-visible="rowsPerPage" />
            </v-col>
        </div>

        <AlertModal :params="alertModalParams"></AlertModal>
    </v-container>
</template>

<script>
import { jsPDF } from 'jspdf';
import 'jspdf-autotable';
import { normal, bold } from '@/assets/font/Pretendard';

import PagePath from '@/components/widget/PagePath';

import * as DateUtil from '@/common/DateUtil';
import * as JsonUtil from '@/common/JsonUtil';
import * as LogUtil from '@/common/LogUtil';
import * as PpaLog from '@/rest/PpaLog';

import AlertModal from '@/components/modal/AlertModal';

export default {
    components: {
        PagePath,
        AlertModal,
    },
    data: () => ({
        alertModalParams: { isOpened: false, title: '', message: '' },

        selectedLogType: null,

        isPickerOpen: false,
        dates: [DateUtil.getBeforeMonth(1), DateUtil.getCurrentDate()],
        checkNum: [],

        headers: [
            { sortable: false },
            { text: 'No', value: 'PPA_LOG_ID', sortable: true },
            { text: '로그 기록 시간', value: 'CREATED' },
            { text: '종류', value: 'LOG_TYPE', sortable: true },
            { text: '메시지', value: 'LOG_DESC', sortable: false },
        ],

        dataList: [],

        isLoading: false,
        sortBy: null,
        sortDesc: null,
        options: {},
        pageNo: 1,
        numOfPages: 0,
        numOfAllData: 0,
        itemsPerPage: [
            { label: '10개씩 보기', value: 10 },
            { label: '20개씩 보기', value: 20 },
            { label: '30개씩 보기', value: 30 },
            { label: '40개씩 보기', value: 40 },
            { label: '50개씩 보기', value: 50 },
        ],
        rowsPerPage: 10,
        selectedRows: [],
    }),
    beforeMount() {
        this.doSearch();
    },
    computed: {
        dateRangeText() {
            return this.dates.join(' ~ ');
        },
    },
    watch: {
        pageNo: {
            handler() {
                this.doSearch();
            },
            deep: true,
        },
        rowsPerPage: {
            handler() {
                this.pageNo = 1;
                this.doSearch();
            },
            deep: true,
        },
        options: {
            handler() {
                this.doSearch();
            },
            deep: true,
        },
    },
    updated() {
        //
    },
    methods: {
        showAlertModal(msg) {
            this.alertModalParams = { isOpened: true, title: 'Warning', message: msg };
        },
        doChangeLogType(logType) {
            this.selectedLogType = logType;
            this.doSearch();
        },
        selectList() {
            setTimeout(() => {
                this.checkNum = document.querySelectorAll('input[type="checkbox"]:checked');
            }, 100);
        },
        checkData() {
            this.selectedRows = [];
            this.checkNum.forEach((checked) => {
                this.dataList.map((item) => {
                    if (item.idx === checked.value * 1) this.selectedRows.push(item);
                });
            });
            console.log('this.selectedRows', this.selectedRows);
        },
        getLogTypeName(selectedLogType) {
            switch (selectedLogType) {
                case 'I':
                    return '정보성';
                case 'N':
                    return '알림';
                case 'W':
                    return '경보성';
                case 'E':
                    return '에러';
                default:
                    return 'Unknown';
            }
        },
        getTimestamp(timestamp) {
            return DateUtil.getTimestamp(timestamp);
        },
        // initDataList(condition) {
        //   let options = {
        //     conditions: [
        //       // { clause: 'and', name: 'MEMBER_TYPE', operator: '=', value: 'H'},
        //     ],
        //     orderBys: [
        //       { name: 'PPA_LOG_ID', operator: 'desc'}
        //     ],
        //     paging: { pageNo: 1, pageSize: this.rowsPerPage }
        //   };
        //   if(condition != null) options.conditions.push(condition);

        //   PpaLog.listByCondition(options).then(res => {
        //     LogUtil.debug('res.data=', res.data);
        //     if(res.data.RES_CODE>=0) {
        //       this.dataList = res.data.ITEMS;
        //       LogUtil.debug("this.dataList=", this.dataList);
        //     } else {
        //       this.showAlertModal(res.data.RES_MSG);
        //     }
        //   }).catch(e => {
        //     LogUtil.error("error=", e);
        //     this.showAlertModal(e);
        //   }).finally(() => {
        //   });
        // },
        getSearchOption() {
            let searchOption = {
                defaultOptions: [],
                dateOptionList: [],
                sortOptions: [{ label: null, id: 'CREATED', value: 'desc' }],
                pagingOption: { pageNo: this.pageNo, pageSize: this.rowsPerPage },
            };

            // 날짜 검색 조건
            searchOption.dateOptions = [{ id: 'CREATED', fromDate: this.dates[0], toDate: this.dates[1] }];

            // 키워드 검색 조건
            // if(this.selectedSearchOption.keywordOption != null
            //   && this.selectedSearchOption.keywordOption.id != null
            //   && this.selectedSearchOption.keyword != null
            //   && this.selectedSearchOption.keyword.length > 0
            // ) {
            //   searchOption.keywordOptions = [{
            //     id: this.selectedSearchOption.keywordOption.id,
            //     value: this.selectedSearchOption.keyword
            //   }];
            // }

            // 코드 검색 조건
            if (this.selectedLogType !== null) {
                searchOption.statusOptions = [{ id: 'LOG_TYPE', value: this.selectedLogType }];
            }

            // DataTable column header 클릭 시 정렬 처리
            if (this.sortBy != null && this.sortBy.length > 0) {
                searchOption.sortOptions = [];
                searchOption.sortOptions.push({ label: null, id: this.sortBy, value: this.sortDesc ? 'asc' : 'desc' });
            }
            return searchOption;
        },
        doSearch() {
            // LogUtil.debug('DocAllList.doSearch(): selectedSearchOption=', this.selectedSearchOption);
            this.selectedRows = [];
            this.isLoading = true;

            let searchOption = this.getSearchOption();
            // LogUtil.debug("searchOption=", searchOption);
            // if(searchOption != null) return;

            PpaLog.listBySearchOption(searchOption)
                .then((res) => {
                    // LogUtil.debug("res.data=", res.data);
                    if (res.data.RES_CODE >= 0) {
                        this.dataList = res.data.ITEMS;
                        if (res.data.ITEMS.length > 0) {
                            this.numOfAllData = res.data.ITEMS[0].COUNT;
                        } else {
                            this.numOfAllData = 0;
                        }
                        this.numOfPages = Math.ceil(this.numOfAllData / this.rowsPerPage);
                        // LogUtil.debug("this.numOfPages=",this.numOfPages,", this.numOfAllData=",this.numOfAllData);
                    } else {
                        this.showAlertModal(res.data.RES_MSG);
                    }
                })
                .catch((e) => {
                    LogUtil.error('error=', e);
                    this.showAlertModal(e);
                })
                .finally(() => {
                    this.isLoading = false;
                });
        },
        doExcelDownload() {
            let header = [];
            this.headers.forEach((item, index) => {
                if (index > 0) header.push(item.text);
            });
            // LogUtil.debug("header=", header);

            let dataList = [];
            this.dataList.forEach((item) => {
                let row = {};
                this.headers.forEach((header, col) => {
                    if (col !== 0) {
                        switch (col) {
                            case 2:
                                row[header.text] = DateUtil.getCurrentTimestamp(item[header.value]);
                                break;
                            case 3:
                                row[header.text] = this.getLogTypeName(item[header.value]);
                                break;
                            default:
                                row[header.text] = item[header.value];
                                break;
                        }
                    }
                });
                dataList.push(row);
            });
            JsonUtil.excelDownload(header, dataList, `로그_${DateUtil.getCurrentTimestampWithNoDelimeter()}`);
        },
        doPdfDownload() {
            let colList = [];
            let rowList = [];

            this.headers.forEach((header, c) => {
                if (c > 0) colList.push({ title: header.text, dataKey: header.value });
            });

            this.dataList.forEach((item, r) => {
                let data = {};
                data[this.headers[1].value] = this.dataList[r].PPA_LOG_ID;
                data[this.headers[2].value] = DateUtil.getCurrentTimestamp(this.dataList[r].CREATED);
                data[this.headers[3].value] = this.getLogTypeName(this.dataList[r].LOG_TYPE);
                data[this.headers[4].value] = this.dataList[r].LOG_DESC;
                rowList.push(data);
            });

            let doc = new jsPDF();
            doc.addFileToVFS('Pretendard-Regular-normal.ttf', normal);
            doc.addFont('Pretendard-Regular-normal.ttf', 'Pretendard-Regular', 'normal');
            doc.setFont('Pretendard-Regular');
            // doc.setFontType('bold');
            doc.autoTable(colList, rowList, {
                theme: 'grid',
                styles: {
                    font: 'Pretendard-Regular',
                    fontStyle: 'normal',
                },
                headerStyles: {
                    fontSize: 15,
                    font: 'Pretendard-Regular',
                    fontStyle: 'normal',
                },
            });

            doc.setProperties({
                title: `로그 ${DateUtil.getCurrentDate()}`,
            });
            doc.save(`로그_${DateUtil.getCurrentTimestampWithNoDelimeter()}.pdf`);
        },
        doPdfDownload_() {
            let doc = new jsPDF();
            let rows = [];
            this.dataList.map(function (item) {
                rows.push({
                    PPA_LOG_ID: item.PPA_LOG_ID,
                    CREATED: item.CREATED,
                    LOG_TYPE: item.LOG_TYPE,
                    LOG_DESC: item.LOG_DESC,
                });
            });
            doc.autotable({
                columns: [
                    { header: 'PPA_LOG_ID', datakey: 'PPA_LOG_ID' },
                    { header: 'CREATED', datakey: 'CREATED' },
                    { header: 'LOG_TYPE', datakey: 'LOG_TYPE' },
                    { header: 'LOG_DESC', datakey: 'LOG_DESC' },
                ],
                body: rows,
                margin: { top: 35 },
                diddrawpage: function (data) {
                    doc.text('tolist articles', 20, 30);
                },
            });
            doc.save('table.pdf');
        },
    },
};
</script>

<style lang="scss" scoped>
.content {
    .list_options {
        @include hCenterAlign();
        .btn_area {
            @include hCenterAlign();
            .txt_term {
                width: 40px;
                margin-right: 7px;
                font {
                    size: 12px;
                }
                color: $color-main02;
            }
            .btn_search {
                margin-left: 5px;
            }
            .category {
                width: 510px;
                margin-left: 20px;
                button {
                    padding: 0 20px;
                    font: {
                        size: 15px;
                    }
                    & + button {
                        margin-left: 10px;
                    }

                    &.btn_all {
                        color: $color-btn01;
                        caret-color: $color-btn01;
                        &.v-btn--is-elevated {
                            color: $color-main02;
                        }
                    }
                    &.btn_info {
                        color: $color-btn02;
                        caret-color: $color-btn02;
                    }
                    &.btn_alarm {
                        color: $color-btn03;
                        caret-color: $color-btn03;
                    }
                    &.btn_alert {
                        color: $color-btn04;
                        caret-color: $color-btn04;
                    }
                    &.btn_error {
                        color: $color-btn05;
                        caret-color: $color-btn05;
                    }
                    &.v-btn--is-elevated {
                        color: $color-main04;
                    }
                }
            }
            & > button {
                width: 30px;
                height: 36px;
                &.btn_xls {
                    background: url('@/assets/history/btn_xls_on.svg') no-repeat 0 0;
                    &:disabled {
                        background-image: url('@/assets/history/btn_xls_off.svg');
                    }
                }
                &.btn_pdf {
                    margin-left: 10px;
                    background: url('@/assets/history/btn_pdf_on.svg') no-repeat 0 0;
                    &:disabled {
                        background-image: url('@/assets/history/btn_pdf_off.svg');
                    }
                }
            }
            .view_length {
                width: 150px;
                margin-left: 10px;
            }
        }
    }
    .v-data-table {
        margin-top: 33px;
        td {
            cursor: pointer;
            .v-input--checkbox {
                height: 46px;
                margin-top: 0;
            }
            .cate_info {
                color: $color-btn02;
            }
            .cate_alarm {
                color: $color-btn03;
            }
            .cate_alert {
                color: $color-btn04;
            }
            .cate_error {
                color: $color-btn05;
            }
        }
    }
    .pagination {
        padding: 0;
        margin-top: 50px;
    }
}
</style>
